// Small wrappers keep generated call sites compact while preserving the
// shared first-error behavior.
func (s *fpState) doStub(name string) {
	if s.err == nil {
		s.err = s.handleStub(name)
	}
}
func (s *fpState) doDPReg(inst uint32) {
	if s.err == nil {
		s.err = fpExecDPReg(&s.cpu, s.mem, inst)
	}
}
func (s *fpState) doSIMD(inst uint32) {
	if s.err == nil {
		s.err = fpExecSIMD(&s.cpu, s.mem, inst)
	}
}

// doSIMDN runs a run of N adjacent SIMD instructions. The codegen
// fold collapses N consecutive `s.doSIMD(inst)` calls into a single
// `s.doSIMDN(...)` line, saving N-1 source lines per run.
func (s *fpState) doSIMDN(insts ...uint32) {
	for _, inst := range insts {
		if s.err != nil {
			return
		}
		s.err = fpExecSIMD(&s.cpu, s.mem, inst)
	}
}

// Helpers used by the generated trace.

// ARM UDIV/SDIV: division by zero returns 0; signed MIN_INT / -1
// returns MIN_INT (no overflow trap).
func fpUDiv32(a, b uint32) uint32 {
	if b == 0 {
		return 0
	}
	return a / b
}
func fpSDiv32(a, b uint32) uint32 {
	if b == 0 {
		return 0
	}
	sa, sb := int32(a), int32(b)
	if sa == -1<<31 && sb == -1 {
		return uint32(sa)
	}
	return uint32(sa / sb)
}

// ternaryU64: helper used by emitted code (Go has no `?:`).
func ternaryU64(cond bool, a, b uint64) uint64 {
	if cond {
		return a
	}
	return b
}

// jmpc: codegen helper for conditional branches. Sets pc and
// returns true iff `cond` is true. Lets the generated dispatcher
// emit each conditional branch as a single-statement gofmt-stable
// `if` (which gofmt keeps on one line):
//
//	if s.jmpc(cond, 0xTARGET) { continue OUTER }
//
// instead of the 4-line gofmt-expanded equivalent. Pure size win
// at the cost of a non-inlined function call per branch taken.
func (s *fpState) jmpc(cond bool, pc uint64) bool {
	if cond {
		s.cpu.pc = pc
		return true
	}
	return false
}

// boolU64 is the codegen specialisation of ternaryU64 for the
// extremely common `cond ? 1 : 0` (flag-bit producer). Inlining it
// gives the SSA backend a chance to lower to a conditional set
// without the helper-function call.
func boolU64(cond bool) uint64 {
	if cond {
		return 1
	}
	return 0
}

// wbU64 forces a uint64 constant to be a runtime value (not a typed
// constant). Used by codegen const-prop so that wide literals can
// flow through `uint32(...)` truncation contexts that would
// otherwise reject a typed constant overflowing uint32.
//
//go:noinline
func wbU64(x uint64) uint64 { return x }

// fpFlags32 wraps fpAddWithCarry32 so the result widens to uint64,
// letting the generated trace emit the entire flag-setting
// add/sub as a single Go statement (no temporary needed for 32-bit
// destinations).
func fpFlags32(a, y, carry uint32) (uint64, bool, bool, bool, bool) {
	r, n, z, c, v := fpAddWithCarry32(a, y, carry)
	return uint64(r), n, z, c, v
}

// stpSP / ldpSP: STP/LDP with SP-relative addressing. Codegen
// post-processes adjacent `s.mem.write64((s.cpu.sp + L), A)` /
// `s.mem.write64((s.cpu.sp+L)+8, B)` pairs into one `s.stpSP(L, A, B)`
// call (and the symmetric LDP form). Each fold saves one source
// line in the generated trace.
func (s *fpState) stpSP(off, lo, hi uint64) {
	sp := s.cpu.sp + off
	s.mem.write64(sp, lo)
	s.mem.write64(sp+8, hi)
}
func (s *fpState) ldpSP(off uint64) (uint64, uint64) {
	sp := s.cpu.sp + off
	return s.mem.read64(sp), s.mem.read64(sp + 8)
}

// stpSPN / ldpSPInto: variadic forms used to collapse runs of N
// adjacent stpSP / ldpSP calls (each writing/reading a 16-byte slot
// at consecutive offsets off, off+0x10, off+0x20, ...). The codegen
// fold rewrites N consecutive 2-reg ops into a single N*2-reg call.
func (s *fpState) stpSPN(off uint64, regs ...uint64) {
	sp := s.cpu.sp + off
	for i, r := range regs {
		s.mem.write64(sp+uint64(i)*8, r)
	}
}
func (s *fpState) ldpSPInto(off uint64, regs ...*uint64) {
	sp := s.cpu.sp + off
	for i, r := range regs {
		*r = s.mem.read64(sp + uint64(i)*8)
	}
}

